+            total_items: None,
+            data: Some(serde_json::json!([[1, 2], [3, 4]])),
+        };
+        let json = serde_json::to_string(&pr).unwrap();
+        let parsed: PartialResult = serde_json::from_str(&json).unwrap();
+        let arr = parsed.data.unwrap();
+        assert!(arr.is_array());
+        assert_eq!(arr.as_array().unwrap().len(), 2);
+    }
